mapper.select:
SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT DISTINCT e.ERROR_CODE, e.TRX_ID, e.ERROR_TITLE, e.LAST_UPDATE_DTIME, e.LAST_UPDATE_USER_ID, e.ORG_ID, e.ORG_ERROR_CODE, (SELECT ed.ERROR_CAUSE_DESC FROM FWK_ERROR_DESC ed WHERE ed.ERROR_CODE = e.ERROR_CODE AND ed.LOCALE_CODE = 'KO' AND ROWNUM = 1) AS ERROR_CAUSE_DESC, e.ERROR_LEVEL, e.ERROR_HTTPCODE, e.FINAL_APPROVAL_STATE, e.FINAL_APPROVAL_DTIME, e.FINAL_APPROVAL_USER_ID, e.FINAL_APPROVAL_USER_NAME, (SELECT LISTAGG(ha.HANDLE_APP_NAME, ', ') WITHIN GROUP (ORDER BY ha.HANDLE_APP_NAME) FROM FWK_ERROR_HANDLE_APP eha2 INNER JOIN FWK_HANDLE_APP ha ON eha2.HANDLE_APP_ID = ha.HANDLE_APP_ID WHERE eha2.ERROR_CODE = e.ERROR_CODE) AS HANDLE_APPS, (SELECT COUNT(*) FROM FWK_ERROR_HIS eh WHERE eh.ERROR_CODE = e.ERROR_CODE) AS ERROR_COUNT FROM FWK_ERROR e
INNER JOIN FWK_ERROR_HANDLE_APP eha ON e.ERROR_CODE = eha.ERROR_CODE
WHERE 1=1
) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}
